import React from 'react';
import { ChevronDown, MoreHorizontal } from 'lucide-react';

const Schedule = () => {
  const scheduleData = [
    {
      day: '02',
      dayName: 'Monday',
      events: [
        {
          id: 1,
          title: 'Team Meeting',
          time: '11:30am - 12:00pm',
          avatar: '👨‍💼',
          additionalPeople: '+3',
          isCurrent: true
        },
        {
          id: 2,
          title: 'Launch break',
          time: '12:00am - 1:00pm',
          isCurrent: false
        },
        {
          id: 3,
          title: 'Product Review',
          time: '13:00pm - 4:30pm',
          isCurrent: false
        }
      ]
    },
    {
      day: '03',
      dayName: 'Tuesday',
      events: [
        {
          id: 4,
          title: 'Daily Meeting',
          time: '09:30am - 10:00am',
          avatar: '👩‍💼',
          isCurrent: false
        },
        {
          id: 5,
          title: 'Clients Meeting',
          time: '10:15am - 12:00pm',
          avatar: 'CL',
          isCurrent: false
        },
        {
          id: 6,
          title: 'Launch break',
          time: '12:00am - 1:00pm',
          isCurrent: false
        },
        {
          id: 7,
          title: 'Free for talk',
          time: '13:00pm - 2:00pm',
          isCurrent: false
        },
        {
          id: 8,
          title: 'Product Review',
          time: '13:00pm - 4:30pm',
          avatar: '👨‍💼',
          additionalPeople: '+3',
          isCurrent: false
        }
      ]
    },
    {
      day: '04',
      dayName: 'Wednesday',
      events: [
        {
          id: 9,
          title: 'Team Meeting',
          time: '11:30am - 12:00am',
          avatar: '👨‍💼',
          additionalPeople: '+3',
          isCurrent: false
        },
        {
          id: 10,
          title: 'Launch break',
          time: '12:00am - 1:00pm',
          isCurrent: false
        }
      ]
    }
  ];

  return (
    <div className="bg-neutral-900 rounded-lg p-6 max-w-md">
      {/* Header */}
      <div className="flex items-center justify-between mb-6">
        <h2 className="text-white text-xl font-semibold">My Schedule</h2>
        <div className="flex items-center gap-2 text-white">
          <span className="text-lg">Jul 2025</span>
          <ChevronDown className="w-5 h-5" />
        </div>
      </div>

      {/* Schedule Days */}
      <div className="space-y-6">
        {scheduleData.map((dayData) => (
          <div key={dayData.day} className="flex gap-4">
            {/* Day Column */}
            <div className="flex flex-col items-center min-w-[60px]">
              <div className="text-white text-2xl font-bold">{dayData.day}</div>
              <div className="text-neutral-400 text-sm">{dayData.dayName}</div>
            </div>

            {/* Events Column */}
            <div className="flex-1 space-y-3">
              {dayData.events.map((event) => (
                <div
                  key={event.id}
                  className={`rounded-lg p-3 ${
                    event.isCurrent
                      ? 'bg-cyan-600'
                      : 'border border-neutral-700 bg-transparent'
                  }`}
                >
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-3 flex-1">
                      {event.avatar && (
                        <div className="flex items-center gap-1">
                          <div className="w-8 h-8 rounded-full bg-neutral-700 flex items-center justify-center text-sm">
                            {event.avatar}
                          </div>
                          {event.additionalPeople && (
                            <span className={`text-sm ${
                              event.isCurrent ? 'text-cyan-200' : 'text-neutral-500'
                            }`}>
                              {event.additionalPeople}
                            </span>
                          )}
                        </div>
                      )}
                      <div className="flex-1">
                        <div className={`font-medium ${
                          event.isCurrent ? 'text-cyan-200' : 'text-neutral-500'
                        }`}>
                          {event.title}
                        </div>
                        <div className="text-white text-sm">{event.time}</div>
                      </div>
                    </div>
                    <MoreHorizontal className={`w-5 h-5 ${
                      event.isCurrent ? 'text-cyan-200' : 'text-neutral-500'
                    }`} />
                  </div>
                </div>
              ))}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default Schedule;
